import sys
import os
import subprocess

try:
    import psycopg2
except ImportError:
    subprocess.check_call([sys.executable, '-m', 'pip', 'install', 'psycopg2-binary'])
    import psycopg2

DB_CONFIG = {
    "host": "172.17.0.1",
    "port": "5432",
    "user": "postgres",
    "password": "password",
    "dbname": "postgres"
}


def run_query(target):
    # If target is a valid file path, read SQL from file; otherwise use as raw SQL
    if os.path.isfile(target):
        with open(target, 'r') as f:
            sql = f.read()
    else:
        sql = target

    conn = psycopg2.connect(**DB_CONFIG)
    conn.autocommit = True
    try:
        cur = conn.cursor()
        cur.execute(sql)

        if cur.description is not None:
            # SELECT-like query: print pipe-separated table with headers
            headers = [desc[0] for desc in cur.description]
            print(" | ".join(headers))
            rows = cur.fetchall()
            for row in rows:
                print(" | ".join("" if v is None else str(v) for v in row))
        else:
            # Non-SELECT query: print success message
            print("Query executed successfully.")

        cur.close()
    finally:
        conn.close()


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Error: missing argument. Usage: python run_db.py <sql_or_path>", file=sys.stderr)
        sys.exit(1)
    try:
        run_query(sys.argv[1])
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)
